# [doc = " Project a [`SwapCertificate`] to an [`ExplainRecord`] ŌĆö total, never fails (C3; G11)."] # [doc = ""] # [doc = " Bijective certificates carry `strength = Exact` and the M-121 `lemma_ref`."] # [doc = " Bounded certificates carry `strength` derived from their basis (never asserted) and their bound."] # [must_use] pub fn explain (cert : & SwapCertificate) -> ExplainRecord { match cert { SwapCertificate :: Bijective { src , target , policy_used , lemma_ref , params , } => ExplainRecord { src : src . clone () , target : target . clone () , policy_used : policy_used . clone () , cert_kind : "Bijective" , lemma_ref : Some (lemma_ref . clone ()) , bound : None , strength : GuaranteeStrength :: Exact , summary : format ! ("Exact bijective swap {src:?} \u{2192} {target:?} \
                 (width={w}, trits={t}); lemma {lemma}; Exact within range" , w = params . width , t = params . trits , lemma = lemma_ref . as_str () ,) , } , SwapCertificate :: Bounded { src , target , policy_used , bound , } => { let strength = bound . basis . strength () ; let bound_desc = match & bound . kind { BoundKind :: Error { eps , norm } => format ! ("\u{03b5}={eps:.2e} ({norm:?})") , BoundKind :: Probability { delta } => format ! ("\u{03b4}={delta:.2e}") , _ => format ! ("{:?}" , bound . kind) , } ; let basis_desc = match & bound . basis { BoundBasis :: ProvenThm { citation } => format ! ("ProvenThm: {citation}") , BoundBasis :: EmpiricalFit { trials , method } => { format ! ("EmpiricalFit ({trials} trials): {method}") } BoundBasis :: UserDeclared => "UserDeclared (unverified)" . to_owned () , } ; ExplainRecord { src : src . clone () , target : target . clone () , policy_used : policy_used . clone () , cert_kind : "Bounded" , lemma_ref : None , bound : Some (bound . clone ()) , strength , summary : format ! ("{strength:?} bounded swap {src:?} \u{2192} {target:?}; \
                     bound={bound_desc}; basis={basis_desc}") , } } } }
